'use client';
import { useState } from 'react';
import ToolWrapper from '../components/ToolWrapper';
import { Scale, RefreshCw, Calculator } from 'lucide-react';

type Unit = 'metric' | 'imperial';

function getCategory(bmi: number) {
  if (bmi >= 18.5 && bmi < 25) return { label: 'Normal weight', color: 'text-emerald-400' };
  if (bmi < 18.5)               return { label: 'Underweight',   color: 'text-red-400' };
  if (bmi < 30)                 return { label: 'Overweight',    color: 'text-red-400' };
  return                               { label: 'Obese',         color: 'text-red-400' };
}

function calcBmi(weight: string, height: string, unit: Unit): number | null {
  const w = parseFloat(weight);
  const h = parseFloat(height);
  if (!w || !h || w <= 0 || h <= 0) return null;
  const raw = unit === 'metric'
    ? w / Math.pow(h / 100, 2)
    : 703 * w / Math.pow(h, 2);
  return raw > 10 && raw < 100 ? parseFloat(raw.toFixed(1)) : null;
}

export default function BmiClient() {
  const [unit,   setUnit]   = useState<Unit>('metric');
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('');
  const [bmi,    setBmi]    = useState<number | null>(null);

  const calculate = () => setBmi(calcBmi(weight, height, unit));
  const reset     = () => { setWeight(''); setHeight(''); setBmi(null); };

  const cat = bmi !== null ? getCategory(bmi) : null;

  return (
    <ToolWrapper
      title="BMI Calculator"
      subtitle="Body mass index from height and weight"
      icon={<Scale size={17} className="text-gray-400" />}
      adSlot="bmi"
    >
      <div className="space-y-8">

        {/* Unit presets */}
        <div className="space-y-3 pb-4">
          <p className="text-base text-zinc-500 uppercase tracking-widest font-medium">Unit</p>
          <div className="flex flex-wrap gap-3">
            {(['metric', 'imperial'] as Unit[]).map(u => (
              <button key={u} onClick={() => { setUnit(u); setBmi(null); }}
                className={`px-6 py-3 rounded-full border text-sm font-medium transition-all ${
                  unit === u
                    ? 'border-emerald-500 text-emerald-400 bg-emerald-950/30'
                    : 'border-zinc-700 text-zinc-300 hover:border-emerald-500 hover:text-emerald-400 hover:bg-emerald-950/30'
                }`}>
                {u === 'metric' ? 'kg / cm' : 'lbs / in'}
              </button>
            ))}
          </div>
        </div>

        {/* Inputs */}
        <div className="grid grid-cols-2 gap-8">
          <div className="space-y-2">
            <label className="text-base text-zinc-400 font-semibold uppercase tracking-wider block">
              Weight
            </label>
            <input
              type="number"
              placeholder={unit === 'metric' ? 'kg' : 'lbs'}
              value={weight}
              onChange={e => setWeight(e.target.value)}
              className="w-full px-5 py-4 bg-zinc-900 border border-zinc-700 rounded-2xl text-white text-base focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
            />
          </div>
          <div className="space-y-2">
            <label className="text-base text-zinc-400 font-semibold uppercase tracking-wider block">
              Height
            </label>
            <input
              type="number"
              placeholder={unit === 'metric' ? 'cm' : 'in'}
              value={height}
              onChange={e => setHeight(e.target.value)}
              className="w-full px-5 py-4 bg-zinc-900 border border-zinc-700 rounded-2xl text-white text-base focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all"
            />
          </div>
        </div>

        {/* Buttons */}
        <div className="flex justify-center gap-3 pt-2">
          <button
            onClick={calculate}
            className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white font-semibold px-8 py-3 rounded-xl text-sm transition-all active:scale-[0.98]"
            style={{ minWidth: '160px' }}
          >
            <Calculator size={16} strokeWidth={2} /> Calculate
          </button>
          <button
            onClick={reset}
            className="flex items-center justify-center w-11 h-11 bg-zinc-900 hover:bg-zinc-800 border border-zinc-700 text-zinc-400 hover:text-white rounded-xl transition-all"
          >
            <RefreshCw size={14} strokeWidth={2} />
          </button>
        </div>

        {/* Result */}
        {bmi !== null && cat && (
          <div className="space-y-3 pt-10 border-t border-zinc-800 text-center">
            <p className="text-base text-zinc-500 uppercase tracking-widest font-medium">Your BMI</p>
            <p className={`text-[96px] font-black tracking-tighter leading-none tabular-nums ${cat.color}`}>
              {bmi}
            </p>
            <p className={`text-lg font-semibold ${cat.color}`}>{cat.label}</p>
          </div>
        )}

      </div>
    </ToolWrapper>
  );
}
